package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Rszppo;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplStatuutDmfappl;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import com.google.common.collect.ImmutableSet;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.util.Objects;
import java.util.Set;

@AllArgsConstructor
public class FlexiJobsUtil {

    private static final Set<DmfapplWnkengetal> WNKENGETAL_FLEXIJOBS = ImmutableSet.of(DmfapplWnkengetal.HANDARB_FLEXIJOB, DmfapplWnkengetal.HOOFDARB_FLEXIJOB);

    private static final Set<String> NACE_CODES_FLEXIJOBS =
            ImmutableSet.of("86101", "86102", "86103", "86104", "86109", "86210", "86901", "86903", "86905", "86906", "86909", "87101", "87109", "87301", "87302",
                    "86220", "86230", "86907", "87203", "87205", "88102");

    private static final Set<String> NACE_CODES_FLEXIJOBS_2024 =
            ImmutableSet.of("90012", "90029", "90031", "90032", "90041", "90042", "93199");

    private static final Set<String> NACE_CODES_FLEXIJOBS_01_04_2024 =
            ImmutableSet.of("85102", "85103", "85105", "85202", "85203", "85205", "85312", "85313", "85322", "85323", "85325",
                    "85410", "85421", "85591", "85601", "88911", "88912", "88919", "90021", "93110", "93191");

    private static final Set<String> NACE_CODES_FLEXIJOBS_01_01_2025 =
            ImmutableSet.of("85102", "85103", "85105", "85202", "85203", "85205", "85312", "85313", "85322", "85323", "85325", "85330", "85401", "85591", "85691",
                    "86101", "86102", "86103", "86104", "86109", "86210", "86220", "86230", "86910", "86920", "86940", "86951", "86952", "86959", "86991", "86993",
                    "86994", "86995", "86996", "86999", "87101", "87109", "87203", "87205", "87301", "87302", "88102", "88911", "88912", "88919", "90111", "90112",
                    "90120", "90130", "90202", "90311", "90312", "90391", "90399", "91300", "93110", "93121", "93122", "93123", "93124", "93125", "93126", "93127",
                    "93128", "93129", "93130", "93191", "93192", "93199");

    private static final LocalDate GRENS_NACE_CODES_FLEXIJOBS_01_01_2024 = new LocalDate(2024, 1, 1);

    private static final LocalDate GRENS_NACE_CODES_FLEXIJOBS_01_04_2024 = new LocalDate(2024, 4, 1);

    public ConstantManager constantManager;

    public boolean isNaceFoutFlexiJob(Opdracht opdracht, RekenTijd rekenTijd) {
        return opdracht.getHoedanigheid() == Hoedanigheid.TIJDELIJKEN_EN_CONTRACTUELEN &&
                opdracht.getOpperSlices().stream().anyMatch(opper -> isNaceFoutFlexiJob(opper, rekenTijd));
    }

    public boolean isFlexiJob(Opdracht opdracht, RekenTijd rekenTijd) {
        return opdracht.getHoedanigheid() == Hoedanigheid.TIJDELIJKEN_EN_CONTRACTUELEN &&
                opdracht.getOpperSlices().stream().anyMatch(opper -> isFlexiJob(opper, rekenTijd));
    }

    public boolean isFlexiJob(Opper opper, RekenTijd rekenTijd) {
        Rszppo rszppo = opper.getRszppo();
        return checkNaceCodeFlexiJob(rszppo, rekenTijd) && isWnKengetalFlexiJob(rszppo);
    }

    public boolean isNaceFoutFlexiJob(Opper opper, RekenTijd rekenTijd) {
        Rszppo rszppo = opper.getRszppo();
        return !checkNaceCodeFlexiJob(rszppo, rekenTijd) && isWnKengetalFlexiJob(rszppo);
    }

    public boolean checkNaceCodeFlexiJob(Rszppo rszppo, RekenTijd rekenTijd) {
        LocalDate startDatumNace2025 = constantManager.getByCodeDatum(Konstanten.KST_STARTDATUM_NACE_2025, rekenTijd.eindDatum).getDatum();
        String naceCodeSafe = getNaceCodeSafe(rszppo);
        if (rekenTijd.beginDatum.isBefore(GRENS_NACE_CODES_FLEXIJOBS_01_01_2024)) {
            return NACE_CODES_FLEXIJOBS.contains(naceCodeSafe);
        } else if (rekenTijd.beginDatum.isBefore(GRENS_NACE_CODES_FLEXIJOBS_01_04_2024)) {
            return Objects.equals(DmfapplStatuutDmfappl.REDDER.getCode(), rszppo.getStatuutDmfapplCode())
                    || NACE_CODES_FLEXIJOBS.contains(naceCodeSafe)
                    || NACE_CODES_FLEXIJOBS_2024.contains(naceCodeSafe);
        } else if (rekenTijd.beginDatum.isBefore(startDatumNace2025)) {
            return Objects.equals(DmfapplStatuutDmfappl.REDDER.getCode(), rszppo.getStatuutDmfapplCode())
                    || NACE_CODES_FLEXIJOBS.contains(naceCodeSafe)
                    || NACE_CODES_FLEXIJOBS_2024.contains(naceCodeSafe)
                    || NACE_CODES_FLEXIJOBS_01_04_2024.contains(naceCodeSafe);
        } else {
            return Objects.equals(DmfapplStatuutDmfappl.REDDER.getCode(), rszppo.getStatuutDmfapplCode())
                    || NACE_CODES_FLEXIJOBS_01_01_2025.contains(naceCodeSafe);
        }
    }

    private static String getNaceCodeSafe(Rszppo rszppo) {
        String nace = rszppo.getNaceCode();
        return nace != null ? nace.trim() : "";
    }

    public static boolean isWnKengetalFlexiJob(Rszppo rszppo) {
        return WNKENGETAL_FLEXIJOBS.contains(rszppo.getWerknemersKengetal());
    }
}
